   481→ * Used for both student profiles and buddy matching.
   482→ */
   483→export type LearningDifference =
   484→  | 'dyslexia'
   485→  | 'dyscalculia'
   486→  | 'dysgraphia'
   487→  | 'adhd'
   488→  | 'autism'
   489→  | 'cerebralPalsy'
   490→  | 'visualImpairment'
   491→  | 'auditoryProcessing';
