   494→ * Role of support characters in the Support Triangle.
   495→ */
   496→export type SupportRole = 'learning_coach' | 'peer_buddy';
   497→
   498→/**
   499→ * Gender option for support characters.
   500→ * Students can choose their preferred coach/buddy gender.
   501→ */
   502→export type CharacterGender = 'male' | 'female';
   503→
   504→/**
   505→ * Extended student profile with learning differences.
   506→ * Used by Mario/Noemi buddies to personalize their approach.
   507→ */
   508→export interface ExtendedStudentProfile extends StudentProfile {
   509→  learningDifferences: LearningDifference[];
   510→  preferredCoach?: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
   511→  preferredBuddy?: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
   512→}
   513→
   514→/**
   515→ * Support Teacher (Melissa/Roberto) - Learning Coach role.
   516→ * Focus: develop autonomy and study method.
   517→ * Relationship: vertical (coach), but talks "alongside" not "from above".
   518→ */
   519→export interface SupportTeacher {
   520→  id: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
   521→  name: string;
   522→  gender: CharacterGender;
   523→  age: number;
   524→  personality: string;
   525→  role: 'learning_coach';
   526→  voice: MaestroVoice;
   527→  voiceInstructions: string;
   528→  systemPrompt: string;
   529→  greeting: string;
   530→  avatar: string;
