   535→ * MirrorBuddy (Mario/Noemi) - Peer Support role.
   536→ * Focus: make student feel less alone.
   537→ * Relationship: horizontal (friend), speaks as peer.
   538→ *
   539→ * System prompt is dynamic based on student profile:
   540→ * - Age is always student.age + 1
   541→ * - Learning differences mirror the student's
   542→ */
   543→export interface BuddyProfile {
   544→  id: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
   545→  name: string;
   546→  gender: CharacterGender;
   547→  ageOffset: number; // Always 1 (one year older)
   548→  personality: string;
   549→  role: 'peer_buddy';
   550→  voice: MaestroVoice;
   551→  voiceInstructions: string;
   552→  /**
   553→   * Dynamic system prompt generator.
   554→   * Takes student profile to personalize Mario/Maria's background.
   555→   */
   556→  getSystemPrompt: (student: ExtendedStudentProfile) => string;
   557→  /**
   558→   * Dynamic greeting generator.
   559→   */
   560→  getGreeting: (student: ExtendedStudentProfile) => string;
   561→  avatar: string;
   562→  color: string;
   563→}
   564→
   565→/**
   566→ * Union type for any support character (coach or buddy).
   567→ */
   568→export type SupportCharacter = SupportTeacher | BuddyProfile;
   569→
   570→/**
   571→ * Character type identifier for routing.
   572→ * Note: 'support_assistant' was removed in Issue #16 - coaches handle platform support directly.
   573→ */
   574→export type CharacterType = 'maestro' | 'coach' | 'buddy';
   575→
   576→// === PARENT DASHBOARD TYPES ===
   577→
   578→/**
   579→ * Observation category for what each Maestro observes.
   580→ * Maps to the Maestro's specialty and observation focus.
   581→ */
   582→export type ObservationCategory =
   583→  | 'logical_reasoning'       // Archimede
   584→  | 'creativity'              // Leonardo
   585→  | 'verbal_expression'       // Dante
   586→  | 'study_method'            // Montessori
   587→  | 'critical_thinking'       // Socrate
   588→  | 'artistic_sensitivity'    // Mozart
   589→  | 'scientific_curiosity'    // Darwin
   590→  | 'spatial_memory'          // Marco Polo
   591→  | 'historical_understanding' // Giulio Cesare
   592→  | 'mathematical_intuition'  // Pitagora
   593→  | 'linguistic_ability'      // Cicerone
   594→  | 'philosophical_depth'     // Aristotele
   595→  | 'physical_awareness'      // Ippocrate
   596→  | 'experimental_approach'   // Galileo
   597→  | 'environmental_awareness' // Plinio
   598→  | 'collaborative_spirit'    // Alessandro Magno
   599→  | 'narrative_skill';        // Omero
   600→
   601→/**
   602→ * Single observation from a Maestro about the student.
   603→ */
   604→export interface MaestroObservation {
   605→  id: string;
   606→  maestroId: string;
   607→  maestroName: string;
   608→  category: ObservationCategory;
   609→  observation: string;
   610→  isStrength: boolean; // true = punto di forza, false = area di crescita
   611→  confidence: number; // 0-1, how confident the Maestro is
   612→  createdAt: Date;
   613→  sessionId?: string;
   614→}
   615→
   616→/**
   617→ * Suggested strategy for the student.
   618→ */
   619→export interface LearningStrategy {
   620→  id: string;
   621→  title: string;
   622→  description: string;
   623→  suggestedBy: string[]; // Maestro IDs that suggested this
   624→  forAreas: ObservationCategory[];
   625→  priority: 'high' | 'medium' | 'low';
   626→}
   627→
   628→/**
   629→ * Learning style profile.
   630→ */
   631→export interface LearningStyleProfile {
   632→  preferredChannel: 'visual' | 'auditory' | 'kinesthetic' | 'reading_writing';
   633→  optimalSessionDuration: number; // minutes
   634→  preferredTimeOfDay: 'morning' | 'afternoon' | 'evening';
   635→  motivators: string[];
   636→  challengePreference: 'step_by_step' | 'big_picture' | 'mixed';
   637→}
   638→
   639→/**
   640→ * Complete student insights for parent dashboard.
   641→ * Aggregated from all Maestro interactions.
   642→ */
   643→export interface StudentInsights {
   644→  studentId: string;
   645→  studentName: string;
   646→  lastUpdated: Date;
   647→  strengths: MaestroObservation[];
   648→  growthAreas: MaestroObservation[];
   649→  strategies: LearningStrategy[];
   650→  learningStyle: LearningStyleProfile;
   651→  totalSessions: number;
   652→  totalMinutes: number;
   653→  maestriInteracted: string[];
   654→}
   655→
   656→// === AMBIENT AUDIO TYPES ===
   657→
   658→/**
   659→ * Audio focus modes for procedural generation and ambient sounds.
   660→ */
   661→export type AudioMode =
   662→  | 'white_noise'
   663→  | 'pink_noise'
   664→  | 'brown_noise'
   665→  | 'binaural_alpha'    // 8-14 Hz - Relaxed focus
   666→  | 'binaural_beta'     // 14-30 Hz - Active concentration
   667→  | 'binaural_theta'    // 4-8 Hz - Creative, meditative
   668→  | 'rain'
   669→  | 'thunderstorm'
   670→  | 'fireplace'
   671→  | 'cafe'
   672→  | 'library'
   673→  | 'forest'
   674→  | 'ocean'
   675→  | 'night';
   676→
   677→/**
   678→ * Preset combinations of audio modes.
   679→ */
   680→export type AudioPreset =
   681→  | 'deep_work'        // Binaural beta + brown noise
   682→  | 'library'          // Quiet ambience + white noise
   683→  | 'starbucks'        // Café + soft lo-fi
   684→  | 'rainy_day'        // Rain + fireplace + thunder
   685→  | 'nature'           // Forest + birds + wind
   686→  | 'focus'            // Binaural alpha
   687→  | 'creative';        // Binaural theta + nature
   688→
   689→/**
   690→ * Playback state of ambient audio system.
   691→ */
   692→export type AudioPlaybackState = 'idle' | 'playing' | 'paused' | 'loading' | 'error';
   693→
   694→/**
   695→ * Configuration for a single audio layer in the mixer.
   696→ */
   697→export interface AudioLayer {
   698→  id: string;
   699→  mode: AudioMode;
   700→  volume: number;      // 0-1
   701→  enabled: boolean;
   702→}
   703→
   704→/**
   705→ * Ambient audio system state.
   706→ */
   707→export interface AmbientAudioState {
   708→  playbackState: AudioPlaybackState;
   709→  masterVolume: number;        // 0-1
   710→  currentPreset: AudioPreset | null;
   711→  layers: AudioLayer[];
   712→  // Auto-ducking: reduce volume during voice/TTS
   713→  autoDuckEnabled: boolean;
   714→  duckedVolume: number;        // Volume to reduce to when ducking (0-1)
   715→  // Integration with study sessions
   716→  autoStartWithStudy: boolean;
   717→  studySessionAudioMode: AudioMode | null;
   718→  // Error state
   719→  error: string | null;
   720→}
