// ============================================================================
// CONVERGIO WEB - TYPE DEFINITIONS
// Migrated from ConvergioApp native macOS application
// ============================================================================

// === MAESTRO TYPES ===

export type MaestroVoice =
  | 'alloy'
  | 'ash'
  | 'ballad'
  | 'coral'
  | 'echo'
  | 'sage'
  | 'shimmer'
  | 'verse';

export type Subject =
  | 'mathematics'
  | 'physics'
  | 'chemistry'
  | 'biology'
  | 'history'
  | 'geography'
  | 'italian'
  | 'english'
  | 'art'
  | 'music'
  | 'civics'
  | 'economics'
  | 'computerScience'
  | 'health'
  | 'philosophy'
  | 'internationalLaw';

export interface Maestro {
  id: string;
  name: string;
  subject: Subject;
  specialty: string;
  voice: MaestroVoice;
  voiceInstructions: string;  // How to speak/personality for voice
  teachingStyle: string;
  avatar: string;
  color: string;
  systemPrompt: string;
  greeting: string;
}

// === VOICE SESSION TYPES ===

export type VoiceSessionState =
  | 'idle'
  | 'connecting'
  | 'connected'
  | 'listening'
  | 'processing'
  | 'speaking'
  | 'error';

export type VoiceConnectionState = 'idle' | 'connecting' | 'connected' | 'error';

/**
 * Handle returned by useVoiceSession hook.
 * Used to pass voice session state between components without re-creating connections.
 */
export interface VoiceSessionHandle {
  isConnected: boolean;
  isListening: boolean;
  isSpeaking: boolean;
  isMuted: boolean;
  connectionState: VoiceConnectionState;
  connect: (maestro: Maestro, connectionInfo: { provider: 'azure'; proxyPort?: number }) => Promise<void>;
  disconnect: () => void;
  toggleMute: () => void;
}

export type EmotionType =
  | 'neutral'
  | 'joy'
  | 'excitement'
  | 'curiosity'
  | 'confusion'
  | 'frustration'
  | 'anxiety'
  | 'boredom'
  | 'distraction';

export interface Emotion {
  type: EmotionType;
  confidence: number;
  color: string;
}

export interface TranscriptEntry {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  emotion?: Emotion;
}

export interface AudioLevels {
  input: number;
  output: number;
}

// === EDUCATION TYPES ===

export type QuestionType = 'multiple_choice' | 'true_false' | 'open_ended';

export interface Question {
  id: string;
  text: string;
  type: QuestionType;
  options?: string[];
  correctAnswer: string | number;
  hints: string[];
  explanation: string;
  difficulty: 1 | 2 | 3 | 4 | 5;
  subject: Subject;
  topic: string;
}

export interface Quiz {
  id: string;
  title: string;
  subject: Subject;
  questions: Question[];
  timeLimit?: number; // seconds
  masteryThreshold: number; // 0-100
  xpReward: number;
}

export interface QuizResult {
  quizId: string;
  score: number;
  totalQuestions: number;
  correctAnswers: number;
  timeSpent: number;
  masteryAchieved: boolean;
  xpEarned: number;
  completedAt: Date;
}

// === FLASHCARD TYPES (FSRS-5) ===

export type CardState = 'new' | 'learning' | 'review' | 'relearning';
export type Rating = 'again' | 'hard' | 'good' | 'easy';

export interface Flashcard {
  id: string;
  deckId: string;
  front: string;
  back: string;
  state: CardState;
  stability: number;
  difficulty: number;
  elapsedDays: number;
  scheduledDays: number;
  reps: number;
  lapses: number;
  lastReview?: Date;
  nextReview: Date;
}

export interface FlashcardDeck {
  id: string;
  name: string;
  subject: Subject;
  cards: Flashcard[];
  createdAt: Date;
  lastStudied?: Date;
}

// === HOMEWORK TYPES ===

export interface HomeworkStep {
  id: string;
  description: string;
  hints: string[]; // 3 progressive hints
  studentNotes: string;
  completed: boolean;
}

export interface Homework {
  id: string;
  title: string;
  subject: Subject;
  problemType: string;
  steps: HomeworkStep[];
  photoUrl?: string;
  createdAt: Date;
  completedAt?: Date;
}

// === GAMIFICATION TYPES ===

export type MasteryTier =
  | 'beginner'
  | 'intermediate'
  | 'advanced'
  | 'expert'
  | 'master';

export interface SubjectMastery {
  subject: Subject;
  percentage: number;
  tier: MasteryTier;
  topicsCompleted: number;
  totalTopics: number;
  lastStudied?: Date;
}

export interface Streak {
  current: number;
  longest: number;
  lastStudyDate?: Date;
}

export interface Achievement {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: 'study' | 'mastery' | 'streak' | 'social' | 'exploration' | 'xp';
  requirement: number;
  xpReward: number;
  unlockedAt?: Date;
}

export interface Progress {
  xp: number;
  level: number;
  xpToNextLevel: number;
  streak: Streak;
  masteries: SubjectMastery[];
  achievements: Achievement[];
  totalStudyMinutes: number;
  sessionsThisWeek: number;
  questionsAsked: number;
}

// === GRADE TYPES (Italian System) ===

export type GradeType =
  | 'quiz'
  | 'homework'
  | 'test'
  | 'participation'
  | 'project'
  | 'oral';

export interface Grade {
  id: string;
  value: number; // 1-10 Italian scale
  subject: Subject;
  type: GradeType;
  description: string;
  date: Date;
}

export interface SubjectGrades {
  subject: Subject;
  grades: Grade[];
  average: number;
  trend: 'improving' | 'stable' | 'declining';
}

// === STUDENT PROFILE TYPES ===

export type Curriculum =
  | 'liceoClassico'
  | 'liceoScientifico'
  | 'liceoLinguistico'
  | 'liceoArtistico'
  | 'liceoMusicale'
  | 'istitutoTecnico'
  | 'istitutoProfessionale'
  | 'scuolaMedia'
  | 'scuolaElementare';

export type SchoolLevel = 'elementare' | 'media' | 'superiore';

export interface StudentProfile {
  name: string;
  age: number;
  schoolYear: number;
  schoolLevel: SchoolLevel;
  curriculum?: Curriculum;
  // Accessibility
  fontSize: 'small' | 'medium' | 'large' | 'extra-large';
  highContrast: boolean;
  dyslexiaFont: boolean;
  voiceEnabled: boolean;
  simplifiedLanguage: boolean;
  adhdMode: boolean;
}

// === SETTINGS TYPES ===

export type Theme = 'light' | 'dark' | 'system';

export type AIProvider =
  | 'openai'
  | 'anthropic'
  | 'azure'
  | 'gemini'
  | 'openrouter'
  | 'perplexity'
  | 'grok'
  | 'ollama';

export interface Settings {
  theme: Theme;
  provider: AIProvider;
  model: string;
  budgetLimit: number;
  studentProfile: StudentProfile;
}

// === TOOL TYPES ===

export type ToolType =
  | 'run_code'
  | 'create_chart'
  | 'create_diagram'
  | 'create_visualization'
  | 'show_formula'
  | 'create_quiz'
  | 'create_flashcard'
  | 'create_mindmap';

export interface ToolCall {
  id: string;
  type: ToolType;
  name: string;
  arguments: Record<string, unknown>;
  status: 'pending' | 'running' | 'completed' | 'error';
  result?: ToolResult;
}

export interface ToolResult {
  success: boolean;
  output?: string;
  error?: string;
  data?: unknown;
  renderComponent?: string; // Component name to render
}

export interface CodeExecutionRequest {
  language: 'python' | 'javascript';
  code: string;
  timeout?: number;
}

export interface ChartRequest {
  type: 'line' | 'bar' | 'pie' | 'scatter' | 'area';
  title: string;
  data: {
    labels: string[];
    datasets: Array<{
      label: string;
      data: number[];
      color?: string;
    }>;
  };
}

export interface DiagramRequest {
  type: 'flowchart' | 'sequence' | 'class' | 'state' | 'er';
  code: string; // Mermaid syntax (mind maps use MarkMap via create_mindmap tool)
  title?: string;
}

export interface FormulaRequest {
  latex: string;
  description?: string;
}

export interface VisualizationRequest {
  type: 'physics' | 'math' | 'chemistry' | 'biology';
  name: string;
  params: Record<string, number | string>;
}

export interface QuizRequest {
  title: string;
  subject: Subject;
  questions: Array<{
    text: string;
    type: QuestionType;
    options?: string[];
    correctAnswer: string | number;
    hints: string[];
    explanation: string;
    difficulty: 1 | 2 | 3 | 4 | 5;
    topic: string;
  }>;
  masteryThreshold?: number;
  xpReward?: number;
}

export interface FlashcardDeckRequest {
  name: string;
  subject: Subject;
  cards: Array<{
    front: string;
    back: string;
  }>;
}

export interface MindmapRequest {
  title: string;
  nodes: Array<{
    id: string;
    label: string;
    children?: Array<{
      id: string;
      label: string;
      children?: Array<{
        id: string;
        label: string;
      }>;
    }>;
    icon?: string;
    color?: string;
  }>;
}

// === CHAT TYPES ===

export type ChatRole = 'system' | 'user' | 'assistant';

/**
 * Session evaluation data displayed inline in chat.
 * Generated when a Maestro session ends.
 */
export interface SessionEvaluation {
  score: number; // 1-10
  feedback: string; // Maestro's comment
  strengths: string[]; // Punti di forza
  areasToImprove: string[]; // Da migliorare
  sessionDuration: number; // minutes
  questionsAsked: number;
  xpEarned: number;
  savedToDiary: boolean; // If written to Learning table
}

export type ChatMessageType = 'text' | 'voice' | 'evaluation' | 'tool';

export interface ChatMessage {
  id: string;
  role: ChatRole;
  content: string;
  timestamp: Date;
  tokens?: number;
  cost?: number;
  /** Message type for special rendering */
  type?: ChatMessageType;
  /** Evaluation data when type is 'evaluation' */
  evaluation?: SessionEvaluation;
  /** Indicates this was from voice transcript */
  isVoice?: boolean;
}

export interface Conversation {
  id: string;
  title: string;
  messages: ChatMessage[];
  maestroId?: string;
  systemPrompt?: string;
  createdAt: Date;
  updatedAt: Date;
}

// === SUPPORT CHARACTER TYPES (MirrorBuddy v2.0) ===

/**
 * Learning differences that the platform supports.
 * Used for both student profiles and buddy matching.
 */
export type LearningDifference =
  | 'dyslexia'
  | 'dyscalculia'
  | 'dysgraphia'
  | 'adhd'
  | 'autism'
  | 'cerebralPalsy'
  | 'visualImpairment'
  | 'auditoryProcessing';

/**
 * Role of support characters in the Support Triangle.
 */
export type SupportRole = 'learning_coach' | 'peer_buddy';

/**
 * Gender option for support characters.
 * Students can choose their preferred coach/buddy gender.
 */
export type CharacterGender = 'male' | 'female';

/**
 * Extended student profile with learning differences.
 * Used by Mario/Noemi buddies to personalize their approach.
 */
export interface ExtendedStudentProfile extends StudentProfile {
  learningDifferences: LearningDifference[];
  preferredCoach?: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
  preferredBuddy?: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
}

/**
 * Support Teacher (Melissa/Roberto) - Learning Coach role.
 * Focus: develop autonomy and study method.
 * Relationship: vertical (coach), but talks "alongside" not "from above".
 */
export interface SupportTeacher {
  id: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
  name: string;
  gender: CharacterGender;
  age: number;
  personality: string;
  role: 'learning_coach';
  voice: MaestroVoice;
  voiceInstructions: string;
  systemPrompt: string;
  greeting: string;
  avatar: string;
  color: string;
}

/**
 * MirrorBuddy (Mario/Noemi) - Peer Support role.
 * Focus: make student feel less alone.
 * Relationship: horizontal (friend), speaks as peer.
 *
 * System prompt is dynamic based on student profile:
 * - Age is always student.age + 1
 * - Learning differences mirror the student's
 */
export interface BuddyProfile {
  id: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
  name: string;
  gender: CharacterGender;
  ageOffset: number; // Always 1 (one year older)
  personality: string;
  role: 'peer_buddy';
  voice: MaestroVoice;
  voiceInstructions: string;
  /**
   * Dynamic system prompt generator.
   * Takes student profile to personalize Mario/Maria's background.
   */
  getSystemPrompt: (student: ExtendedStudentProfile) => string;
  /**
   * Dynamic greeting generator.
   */
  getGreeting: (student: ExtendedStudentProfile) => string;
  avatar: string;
  color: string;
}

/**
 * Union type for any support character (coach or buddy).
 */
export type SupportCharacter = SupportTeacher | BuddyProfile;

/**
 * Character type identifier for routing.
 * Note: 'support_assistant' was removed in Issue #16 - coaches handle platform support directly.
 */
export type CharacterType = 'maestro' | 'coach' | 'buddy';

// === PARENT DASHBOARD TYPES ===

/**
 * Observation category for what each Maestro observes.
 * Maps to the Maestro's specialty and observation focus.
 */
export type ObservationCategory =
  | 'logical_reasoning'       // Archimede
  | 'creativity'              // Leonardo
  | 'verbal_expression'       // Dante
  | 'study_method'            // Montessori
  | 'critical_thinking'       // Socrate
  | 'artistic_sensitivity'    // Mozart
  | 'scientific_curiosity'    // Darwin
  | 'spatial_memory'          // Marco Polo
  | 'historical_understanding' // Giulio Cesare
  | 'mathematical_intuition'  // Pitagora
  | 'linguistic_ability'      // Cicerone
  | 'philosophical_depth'     // Aristotele
  | 'physical_awareness'      // Ippocrate
  | 'experimental_approach'   // Galileo
  | 'environmental_awareness' // Plinio
  | 'collaborative_spirit'    // Alessandro Magno
  | 'narrative_skill';        // Omero

/**
 * Single observation from a Maestro about the student.
 */
export interface MaestroObservation {
  id: string;
  maestroId: string;
  maestroName: string;
  category: ObservationCategory;
  observation: string;
  isStrength: boolean; // true = punto di forza, false = area di crescita
  confidence: number; // 0-1, how confident the Maestro is
  createdAt: Date;
  sessionId?: string;
}

/**
 * Suggested strategy for the student.
 */
export interface LearningStrategy {
  id: string;
  title: string;
  description: string;
  suggestedBy: string[]; // Maestro IDs that suggested this
  forAreas: ObservationCategory[];
  priority: 'high' | 'medium' | 'low';
}

/**
 * Learning style profile.
 */
export interface LearningStyleProfile {
  preferredChannel: 'visual' | 'auditory' | 'kinesthetic' | 'reading_writing';
  optimalSessionDuration: number; // minutes
  preferredTimeOfDay: 'morning' | 'afternoon' | 'evening';
  motivators: string[];
  challengePreference: 'step_by_step' | 'big_picture' | 'mixed';
}

/**
 * Complete student insights for parent dashboard.
 * Aggregated from all Maestro interactions.
 */
export interface StudentInsights {
  studentId: string;
  studentName: string;
  lastUpdated: Date;
  strengths: MaestroObservation[];
  growthAreas: MaestroObservation[];
  strategies: LearningStrategy[];
  learningStyle: LearningStyleProfile;
  totalSessions: number;
  totalMinutes: number;
  maestriInteracted: string[];
}

// === AMBIENT AUDIO TYPES ===

/**
 * Audio focus modes for procedural generation and ambient sounds.
 */
export type AudioMode =
  | 'white_noise'
  | 'pink_noise'
  | 'brown_noise'
  | 'binaural_alpha'    // 8-14 Hz - Relaxed focus
  | 'binaural_beta'     // 14-30 Hz - Active concentration
  | 'binaural_theta'    // 4-8 Hz - Creative, meditative
  | 'rain'
  | 'thunderstorm'
  | 'fireplace'
  | 'cafe'
  | 'library'
  | 'forest'
  | 'ocean'
  | 'night';

/**
 * Preset combinations of audio modes.
 */
export type AudioPreset =
  | 'deep_work'        // Binaural beta + brown noise
  | 'library'          // Quiet ambience + white noise
  | 'starbucks'        // Café + soft lo-fi
  | 'rainy_day'        // Rain + fireplace + thunder
  | 'nature'           // Forest + birds + wind
  | 'focus'            // Binaural alpha
  | 'creative';        // Binaural theta + nature

/**
 * Playback state of ambient audio system.
 */
export type AudioPlaybackState = 'idle' | 'playing' | 'paused' | 'loading' | 'error';

/**
 * Configuration for a single audio layer in the mixer.
 */
export interface AudioLayer {
  id: string;
  mode: AudioMode;
  volume: number;      // 0-1
  enabled: boolean;
}

/**
 * Ambient audio system state.
 */
export interface AmbientAudioState {
  playbackState: AudioPlaybackState;
  masterVolume: number;        // 0-1
  currentPreset: AudioPreset | null;
  layers: AudioLayer[];
  // Auto-ducking: reduce volume during voice/TTS
  autoDuckEnabled: boolean;
  duckedVolume: number;        // Volume to reduce to when ducking (0-1)
  // Integration with study sessions
  autoStartWithStudy: boolean;
  studySessionAudioMode: AudioMode | null;
  // Error state
  error: string | null;
}

