     1→/**
     2→ * API Route: Materials
     3→ *
     4→ * Persists tool outputs (mindmaps, quizzes, flashcards, etc.) to database.
     5→ * Part of T-20: Persist tools to database + API.
     6→ */
     7→
     8→import { NextRequest, NextResponse } from 'next/server';
     9→import { prisma } from '@/lib/db';
    10→import { logger } from '@/lib/logger';
    11→
    12→// Material types for storage (maps from ToolType actions to stored types)
    13→type MaterialType =
    14→  | 'mindmap'
    15→  | 'quiz'
    16→  | 'flashcard'
    17→  | 'demo'
    18→  | 'webcam'
    19→  | 'pdf'
    20→  | 'search'
    21→  | 'diagram'
    22→  | 'timeline'
    23→  | 'summary'
    24→  | 'formula'
    25→  | 'chart';
    26→
    27→// Valid material types
    28→const VALID_MATERIAL_TYPES: MaterialType[] = [
    29→  'mindmap',
    30→  'quiz',
    31→  'flashcard',
    32→  'demo',
    33→  'webcam',
    34→  'pdf',
    35→  'search',
    36→  'diagram',
    37→  'timeline',
    38→  'summary',
    39→  'formula',
    40→  'chart',
    41→];
    42→
    43→interface CreateMaterialRequest {
    44→  toolId: string;
    45→  toolType: MaterialType;
    46→  title: string;
    47→  content: Record<string, unknown>;
    48→  maestroId?: string;
    49→  sessionId?: string;
    50→  subject?: string;
    51→  preview?: string;
    52→}
    53→
    54→interface UpdateMaterialRequest {
    55→  title?: string;
    56→  content?: Record<string, unknown>;
    57→  status?: 'active' | 'archived' | 'deleted';
    58→  // User interaction (Issue #37 - Archive features)
    59→  userRating?: number;
    60→  isBookmarked?: boolean;
    61→}
    62→
    63→/**
    64→ * GET /api/materials
    65→ * List materials for current user with optional filters
    66→ */
    67→export async function GET(request: NextRequest) {
    68→  try {
    69→    const { searchParams } = new URL(request.url);
    70→    const userId = searchParams.get('userId');
    71→    const toolType = searchParams.get('toolType');
    72→    const status = searchParams.get('status') || 'active';
    73→    const limit = parseInt(searchParams.get('limit') || '50', 10);
    74→    const offset = parseInt(searchParams.get('offset') || '0', 10);
    75→
    76→    if (!userId) {
    77→      return NextResponse.json(
    78→        { error: 'Missing userId parameter' },
    79→        { status: 400 }
    80→      );
    81→    }
    82→
    83→    const where: Record<string, unknown> = { userId, status };
    84→    if (toolType && VALID_MATERIAL_TYPES.includes(toolType as MaterialType)) {
    85→      where.toolType = toolType;
    86→    }
    87→
    88→    const [materials, total] = await Promise.all([
    89→      prisma.material.findMany({
    90→        where,
    91→        orderBy: { createdAt: 'desc' },
    92→        take: Math.min(limit, 100),
    93→        skip: offset,
    94→      }),
    95→      prisma.material.count({ where }),
    96→    ]);
    97→
    98→    // Parse JSON content for each material
    99→    const parsed = materials.map((m: { content: string; [key: string]: unknown }) => ({
   100→      ...m,
   101→      content: JSON.parse(m.content),
   102→    }));
   103→
   104→    return NextResponse.json({
   105→      materials: parsed,
   106→      total,
   107→      limit,
   108→      offset,
   109→    });
   110→  } catch (error) {
   111→    logger.error('Failed to fetch materials', { error: String(error) });
   112→    return NextResponse.json(
   113→      { error: 'Failed to fetch materials' },
   114→      { status: 500 }
   115→    );
   116→  }
   117→}
   118→
   119→/**
   120→ * POST /api/materials
   121→ * Create a new material (persist tool output)
   122→ */
   123→export async function POST(request: NextRequest) {
   124→  try {
   125→    const body: CreateMaterialRequest & { userId: string } = await request.json();
   126→    const { userId, toolId, toolType, title, content, maestroId, sessionId, subject, preview } = body;
   127→
   128→    // Validate required fields
   129→    if (!userId || !toolId || !toolType || !title || !content) {
   130→      return NextResponse.json(
   131→        {
   132→          error: 'Missing required fields',
   133→          required: ['userId', 'toolId', 'toolType', 'title', 'content'],
   134→        },
   135→        { status: 400 }
   136→      );
   137→    }
   138→
   139→    // Validate tool type
   140→    if (!VALID_MATERIAL_TYPES.includes(toolType)) {
   141→      return NextResponse.json(
   142→        {
   143→          error: 'Invalid tool type',
   144→          validTypes: VALID_MATERIAL_TYPES,
   145→        },
   146→        { status: 400 }
   147→      );
   148→    }
   149→
   150→    // Check for duplicate toolId (upsert behavior)
   151→    const existing = await prisma.material.findUnique({
   152→      where: { toolId },
   153→    });
   154→
   155→    if (existing) {
   156→      // Update existing material
   157→      const updated = await prisma.material.update({
   158→        where: { toolId },
   159→        data: {
   160→          title,
   161→          content: JSON.stringify(content),
   162→          preview,
   163→          updatedAt: new Date(),
   164→        },
   165→      });
   166→
   167→      logger.info('Material updated', { toolId, toolType });
   168→
   169→      return NextResponse.json({
   170→        success: true,
   171→        material: {
   172→          ...updated,
   173→          content,
   174→        },
   175→        updated: true,
   176→      });
   177→    }
   178→
   179→    // Create new material
   180→    const material = await prisma.material.create({
   181→      data: {
   182→        userId,
   183→        toolId,
   184→        toolType,
   185→        title,
   186→        content: JSON.stringify(content),
   187→        maestroId,
   188→        sessionId,
   189→        subject,
   190→        preview,
   191→      },
   192→    });
   193→
   194→    logger.info('Material created', { toolId, toolType, userId });
   195→
   196→    return NextResponse.json({
   197→      success: true,
   198→      material: {
   199→        ...material,
   200→        content,
   201→      },
   202→      created: true,
   203→    });
   204→  } catch (error) {
   205→    logger.error('Failed to create material', { error: String(error) });
   206→    return NextResponse.json(
   207→      { error: 'Failed to create material' },
   208→      { status: 500 }
   209→    );
   210→  }
   211→}
   212→
   213→/**
   214→ * PATCH /api/materials
   215→ * Update a material (title, content, or status)
   216→ */
   217→export async function PATCH(request: NextRequest) {
   218→  try {
   219→    const body: UpdateMaterialRequest & { toolId: string } = await request.json();
   220→    const { toolId, title, content, status, userRating, isBookmarked } = body;
   221→
   222→    if (!toolId) {
   223→      return NextResponse.json(
   224→        { error: 'Missing toolId' },
   225→        { status: 400 }
   226→      );
   227→    }
   228→
   229→    const existing = await prisma.material.findUnique({
   230→      where: { toolId },
   231→    });
   232→
   233→    if (!existing) {
   234→      return NextResponse.json(
   235→        { error: 'Material not found' },
   236→        { status: 404 }
   237→      );
   238→    }
   239→
   240→    const updateData: Record<string, unknown> = {};
   241→    if (title) updateData.title = title;
   242→    if (content) updateData.content = JSON.stringify(content);
   243→    if (status) updateData.status = status;
   244→    // User interaction fields (Issue #37)
   245→    if (typeof userRating === 'number' && userRating >= 1 && userRating <= 5) {
   246→      updateData.userRating = userRating;
   247→    }
   248→    if (typeof isBookmarked === 'boolean') {
   249→      updateData.isBookmarked = isBookmarked;
   250→    }
   251→
   252→    const updated = await prisma.material.update({
   253→      where: { toolId },
   254→      data: updateData,
   255→    });
   256→
   257→    logger.info('Material patched', { toolId, fields: Object.keys(updateData) });
   258→
   259→    return NextResponse.json({
   260→      success: true,
   261→      material: {
   262→        ...updated,
   263→        content: content || JSON.parse(updated.content),
   264→      },
   265→    });
   266→  } catch (error) {
   267→    logger.error('Failed to update material', { error: String(error) });
   268→    return NextResponse.json(
   269→      { error: 'Failed to update material' },
   270→      { status: 500 }
   271→    );
   272→  }
   273→}
   274→
   275→/**
   276→ * DELETE /api/materials
   277→ * Soft-delete a material (sets status to 'deleted')
   278→ */
   279→export async function DELETE(request: NextRequest) {
   280→  try {
   281→    const { searchParams } = new URL(request.url);
   282→    const toolId = searchParams.get('toolId');
   283→
   284→    if (!toolId) {
   285→      return NextResponse.json(
   286→        { error: 'Missing toolId parameter' },
   287→        { status: 400 }
   288→      );
   289→    }
   290→
   291→    const existing = await prisma.material.findUnique({
   292→      where: { toolId },
   293→    });
   294→
   295→    if (!existing) {
   296→      return NextResponse.json(
   297→        { error: 'Material not found' },
   298→        { status: 404 }
   299→      );
   300→    }
   301→
   302→    // Soft delete
   303→    await prisma.material.update({
   304→      where: { toolId },
   305→      data: { status: 'deleted' },
   306→    });
   307→
   308→    logger.info('Material deleted', { toolId });
   309→
   310→    return NextResponse.json({
   311→      success: true,
   312→      toolId,
