// ============================================================================
// TOOL PERSISTENCE
// Database operations for saving and retrieving created tools
// Issue #22: Materials Archive - Tool Storage
// ============================================================================

import { prisma } from '@/lib/db';
import type { ToolType } from '@/types/tools';

// ============================================================================
// TYPES
// ============================================================================

export interface SaveToolParams {
  userId: string;
  type: ToolType;
  title: string;
  topic?: string;
  content: Record<string, unknown>;
  maestroId?: string;
  conversationId?: string;
  sessionId?: string;
}

export interface SavedTool {
  id: string;
  userId: string;
  type: string;
  title: string;
  topic: string | null;
  content: Record<string, unknown>;
  maestroId: string | null;
  conversationId: string | null;
  sessionId: string | null;
  userRating: number | null;
  isBookmarked: boolean;
  viewCount: number;
  createdAt: Date;
  updatedAt: Date;
}

export interface GetToolsFilter {
  type?: ToolType;
  maestroId?: string;
  isBookmarked?: boolean;
  limit?: number;
  offset?: number;
}

// ============================================================================
// CRUD OPERATIONS
// ============================================================================

/**
 * Save a tool to the database
 */
export async function saveTool(params: SaveToolParams): Promise<SavedTool> {
  const tool = await prisma.createdTool.create({
    data: {
      userId: params.userId,
      type: params.type,
      title: params.title,
      topic: params.topic ?? null,
      content: JSON.stringify(params.content),
      maestroId: params.maestroId ?? null,
      conversationId: params.conversationId ?? null,
      sessionId: params.sessionId ?? null,
    },
  });

  return {
    ...tool,
    content: JSON.parse(tool.content) as Record<string, unknown>,
  };
}

/**
 * Get all tools for a user with optional filtering
 */
export async function getUserTools(
  userId: string,
  filter?: GetToolsFilter
): Promise<SavedTool[]> {
  const where: Record<string, unknown> = { userId };

  if (filter?.type) {
    where.type = filter.type;
  }
  if (filter?.maestroId) {
    where.maestroId = filter.maestroId;
  }
  if (filter?.isBookmarked !== undefined) {
    where.isBookmarked = filter.isBookmarked;
  }

  const tools = await prisma.createdTool.findMany({
    where,
    orderBy: { createdAt: 'desc' },
    take: filter?.limit ?? 50,
    skip: filter?.offset ?? 0,
  });

  return tools.map((tool) => ({
    ...tool,
    content: JSON.parse(tool.content) as Record<string, unknown>,
  }));
}

/**
 * Get a single tool by ID
 */
export async function getToolById(
  toolId: string,
  userId: string
): Promise<SavedTool | null> {
  const tool = await prisma.createdTool.findFirst({
    where: { id: toolId, userId },
  });

  if (!tool) return null;

  return {
    ...tool,
    content: JSON.parse(tool.content) as Record<string, unknown>,
  };
}

/**
 * Delete a tool
 */
export async function deleteTool(toolId: string, userId: string): Promise<boolean> {
  const result = await prisma.createdTool.deleteMany({
    where: { id: toolId, userId },
  });
  return result.count > 0;
}

/**
 * Update a tool's rating (1-5 stars)
 */
export async function updateToolRating(
  toolId: string,
  userId: string,
  rating: number
): Promise<SavedTool | null> {
  if (rating < 1 || rating > 5) {
    throw new Error('Rating must be between 1 and 5');
  }

  const tool = await prisma.createdTool.updateMany({

/**
 * ConvergioEdu Profile Generator
 *
 * Generates and synthesizes student profiles from Maestri observations.
 * Uses Melissa (Learning Coach) to create balanced, growth-mindset profiles.
 *
 * Part of F-02: Profile Generation from Maestri
 * Related: #31 Collaborative Student Profile
 */

import type {
  StudentInsights,
  MaestroObservation,
  LearningStrategy,
  LearningStyleProfile,
  ObservationCategory,
} from '@/types';

// ============================================================================
// TYPES
// ============================================================================

/**
 * Raw insight collected from a Maestro interaction.
 */
export interface MaestroInsightInput {
  maestroId: string;
  maestroName: string;
  category: ObservationCategory;
  content: string;
  isStrength: boolean;
  confidence: number;
  sessionId?: string;
  createdAt: Date;
}

/**
 * Options for profile generation.
 */
export interface ProfileGenerationOptions {
  /** Maximum insights to process */
  maxInsights?: number;
  /** Minimum confidence threshold for inclusion */
  minConfidence?: number;
  /** Whether to include AI synthesis */
  includeSynthesis?: boolean;
}

/**
 * Context for Melissa's profile synthesis.
 */
interface SynthesisContext {
  studentName: string;
  strengths: MaestroInsightInput[];
  growthAreas: MaestroInsightInput[];
  recentSessions: number;
  totalMinutes: number;
}

// ============================================================================
// CONSTANTS
// ============================================================================

/**
 * Default options for profile generation.
 */
const DEFAULT_OPTIONS: Required<ProfileGenerationOptions> = {
  maxInsights: 100,
  minConfidence: 0.6,
  includeSynthesis: true,
};

/**
 * Category priority for strategy generation.
 */
const CATEGORY_PRIORITY: Record<ObservationCategory, number> = {
  logical_reasoning: 10,
  mathematical_intuition: 9,
  critical_thinking: 9,
  study_method: 10,
  verbal_expression: 8,
  linguistic_ability: 8,
  creativity: 7,
  artistic_sensitivity: 7,
  scientific_curiosity: 8,
  experimental_approach: 7,
  spatial_memory: 6,
  historical_understanding: 6,
  philosophical_depth: 7,
  physical_awareness: 5,
  environmental_awareness: 5,
  narrative_skill: 7,
  collaborative_spirit: 6,
};

/**
 * Strategy suggestions for each observation category.
