    </div>
  </section>

  <footer>
    <p>Questo profilo è stato generato da ConvergioEdu</p>
    <p>La Scuola Che Vorrei - Supporto personalizzato per studenti con differenze di apprendimento</p>
  </footer>
</body>
</html>
  `.trim();
}

